# define species sizes
sizes &lt;- c(1, 0.6, 0.3, 0.1)

# define species diet
diet &lt;- c(0, 1, 0, 1)

# define initial population sizes
pop_t0 &lt;- c(50, 50, 50, 50)

# define carrying capacities
ks &lt;- c(100, 100, 100, 100)

# create an interaction matrix 
interaction_matrix &lt;- matrix(NA, nrow = length(sizes), ncol = length(sizes))

# populate interaction matrix
for(i in 1:length(sizes)) {
  for(j in 1:length(sizes)) {
    if(i == j) {
      interaction_matrix[i, j] &lt;- 0
    } else if(diet[i] == 1 && diet[j] == 0) {
      interaction_matrix[i, j] &lt;- sizes[i]/sizes[j] * 0.25
    } else {
      interaction_matrix[i, j] &lt;- 0
    }
  }
}

# loop to simulate population dynamics
timesteps &lt;- 100

# create a data frame to store population sizes over time
populations &lt;- data.frame(time = 1:timesteps)
for(i in 1:length(sizes)) {
  populations[[paste0("species_", i)]] &lt;- NA
}

# loop to simulate population dynamics
for(t in 1:timesteps) {
  if(t == 1) {
    populations[t, 2:(length(sizes) + 1)] &lt;- pop_t0
  } else {
    for(i in 1:length(sizes)) {
      growth_rate &lt;- 0.1 * (1 - populations[t-1, i + 1] / ks[i])
      interaction_effect &lt;- sum(interaction_matrix[i, ] * populations[t-1, 2:(length(sizes) + 1)])
      populations[t, i + 1] &lt;- populations[t-1, i + 1] + growth_rate * populations[t-1, i + 1] + interaction_effect
    }
  }
}

# plot population dynamics
populations |&gt; 
  pivot_longer(cols = -time, names_to = "species", values_to = "population") |&gt;
  #filter(species == "species_1") |&gt;
  #mutate(species = factor(species, levels = paste0("species_", 1:length(sizes)))) |&gt;
  ggplot(aes(x = time, y = population, color = species)) +
  geom_line()

Defining functions
First, I define a TPC function based on Deutsch et al. (2008). This function uses Topt, CTmin, and CTmax to calculate the performance of an organism at a given body temperature. These parameters are often estimated from empirical data so it makes the whole thing very easily interpretable.


Defining TPC function
# define TPC function
tpc &lt;- function(temps, topt, ctmin, ctmax) {

  # initialize performance vector and define psig
  perf &lt;- rep(NA, length(temps))
  psig &lt;- -((ctmin - topt) / 4)

  # calculate performance
  for (i in seq_along(temps)){
    if (temps[i] &lt; topt) {
      perf[i] &lt;- exp(-((temps[i] - topt) / (2 * psig))^2)
    } else {
      perf[i] &lt;- 1 - ((temps[i] - topt) / (topt - ctmax))^2
    }
  }

  # correct for negative values and return
  ifelse(perf &lt; 0, 0, perf)

}

# example usage
temps &lt;- seq(0, 40, by = 0.1)
topt &lt;- 25
ctmin &lt;- 10
ctmax &lt;- 35
tpc_values &lt;- tpc(temps, topt, ctmin, ctmax)
tibble(temps, tpc_values) |&gt;
  ggplot(aes(x = temps, y = tpc_values)) +
  geom_line(linewidth = 2) +
  labs(x = "Body Temperature (°C)", y = "Performance") +
  theme_minimal()









Second, I define a function that generates a skew-normal distribution of body temperatures based on a mean, standard deviation, and skewness parameter. To do this I use two functions:

cp2dp() from the sn package to convert the mean, sd, and skewness parameters to the location, scale, and shape parameters of the skew-normal distribution.
dsn() from the sn package to calculate the density of the skew-normal distribution at a given set of body temperatures.



Defining function to generate body temperature distributions
gen_tb_distrib &lt;- function(temps, mean, sd, skew) {

  # stop if SD is negative or if skew is outside of -1 to 1
  if (sd &lt; 0) stop("SD must be non-negative")
  if (skew &lt;= -1 || skew &gt;= 1) stop("Skew must be between -0.99 and 0.99")

  # estimate the parameters of the skew-normal distribution
  params &lt;- cp2dp(c(mean, sd, skew), "SN")

  # generate a sequence of body temperatures and calculate the density
  dsn(temps, xi = params[1], omega = params[2], alpha = params[3])

}

# example usage
tb_distrib &lt;- gen_tb_distrib(
  temps = seq(0, 50, by = 0.1), mean = 25, sd = 5, skew = 0.5
)
tibble(temps = seq(0, 50, by = 0.1), density = tb_distrib) |&gt;
  ggplot(aes(x = temps, y = density)) +
  geom_line(linewidth = 2) +
  labs(x = "Body Temperature (°C)", y = "Density") +
  theme_minimal()









Third, I define a function to calculate the expected fitness of a TPC under a given body temperature distribution. I do this using the Vasseur et al. (2014) approach, which is based on integrating the product of the TPC and the body temperature distribution across all possible body temperatures.


Defining function to calculate expected fitness
exp_fitness &lt;- function(topt, ctmin, ctmax, mean_tb, sd_tb, skew_tb) {

  if (sd_tb == 0) {
    tpc(mean_tb, topt, ctmin, ctmax)

  } else {
    # function to calculate integrand
    integrand &lt;- function(temps) {
      tpc(temps, topt, ctmin, ctmax) *  gen_tb_distrib(temps, mean_tb, sd_tb, skew_tb) # nolint
    }

    # integrate
    integrate(integrand, lower = -30, upper = 60)$value
  }
}

# example usage
exp_fitness(topt = 25, ctmin = 10, ctmax = 35, mean_tb = 25, sd_tb = 5, skew_tb = 0.5) # nolint


